1	//! Heuristic distraction classifier.
2	//!
3	//! Runs at intake, before any eye perceives content. Three-stage pipeline:
4	//! 1. URL patterns — ad/tracking domains, redirect detection
5	//! 2. DOM content patterns — cookie banners, newsletter modals, surveys
6	//! 3. CSS class/id hints — overlay, popup, ad-related selectors
7	//!
8	//! Target: <1ms classification time for typical pages (5000 elements).
9	
10	use ans_core::immune::{DistractionFlag, DistractionKind, ImmuneAction};
11	
12	use crate::rules::{self, Rule};
13	
14	/// The heuristic distraction classifier.
15	pub struct DistractionClassifier;
16	
17	impl DistractionClassifier {
18	    /// Classify all distractions on a page.
19	    ///
20	    /// `dom_text` should be all visible text from the distilled DOM,
21	    /// concatenated for pattern matching. `css_hints` is the raw HTML
22	    /// snippet or attribute strings for class/id pattern matching.
23	    pub fn classify(&self, url: &str, dom_text: &str, css_hints: &str) -> Vec<DistractionFlag> {
24	        let mut flags = Vec::new();
25	
26	        // Stage 1: URL-based rules
27	        for rule in &rules::url_rules() {
28	            if rule.pattern.is_match(url) {
29	                flags.push(flag_from_rule(rule));
30	            }
31	        }
32	
33	        // Stage 2: Content-based rules
34	        for rule in &rules::content_rules() {
35	            if rule.pattern.is_match(dom_text) {
36	                flags.push(flag_from_rule(rule));
37	            }
38	        }
39	
40	        // Stage 3: CSS class/id hint rules
41	        for rule in &rules::css_hint_rules() {
42	            if rule.pattern.is_match(css_hints) {
43	                flags.push(flag_from_rule(rule));
44	            }
45	        }
46	
47	        // Deduplicate by kind, keeping the higher confidence
48	        deduplicate(&mut flags);
49	
50	        flags
51	    }
52	}
53	
54	/// Map a matched rule to a [`DistractionFlag`].
55	fn flag_from_rule(rule: &Rule) -> DistractionFlag {
56	    DistractionFlag {
57	        kind: str_to_kind(&rule.kind),
58	        element_selector: String::new(),
59	        confidence: rule.confidence,
60	        suggested_action: str_to_action(&rule.action),
61	    }
62	}
63	
64	/// Deduplicate flags: keep only one per kind, preferring higher confidence.
65	fn deduplicate(flags: &mut Vec<DistractionFlag>) {
66	    let mut seen: std::collections::BTreeMap<String, usize> = std::collections::BTreeMap::new();
67	    let mut i = 0;
68	    while i < flags.len() {
69	        let kind_key = format!("{:?}", flags[i].kind);
70	        if let Some(&existing_idx) = seen.get(&kind_key) {
71	            if flags[existing_idx].confidence < flags[i].confidence {
72	                flags.remove(existing_idx);
73	                // Rebuild — safe because this is rare (<20 flags)
74	                seen.clear();
75	                i = 0;
76	                continue;
77	            } else {
78	                flags.remove(i);
79	                continue;
80	            }
81	        } else {
82	            seen.insert(kind_key, i);
83	        }
84	        i += 1;
85	    }
86	}
87	
88	fn str_to_kind(s: &str) -> DistractionKind {
89	    match s {
90	        "ad" => DistractionKind::Ad,
91	        "popup" => DistractionKind::Popup,
92	        "cookie_banner" => DistractionKind::CookieBanner,
93	        "newsletter_modal" => DistractionKind::NewsletterModal,
94	        "redirect" => DistractionKind::Redirect,
95	        "autoplay_video" => DistractionKind::AutoPlayVideo,
96	        "survey" => DistractionKind::Survey,
97	        "notification" => DistractionKind::Notification,
98	        _ => DistractionKind::Unknown,
99	    }
100	}
101	
102	fn str_to_action(s: &str) -> ImmuneAction {
103	    match s {
104	        "dismiss" => ImmuneAction::Dismiss,
105	        "block" => ImmuneAction::Block,
106	        "suppress" => ImmuneAction::Suppress,
107	        "ignore" => ImmuneAction::Ignore,
108	        "navigate_back" => ImmuneAction::NavigateBack,
109	        _ => ImmuneAction::Ignore,
110	    }
111	}
112	
113	#[cfg(test)]
114	mod tests {
115	    use super::*;
116	
117	    #[test]
118	    fn test_ad_url_detected() {
119	        let c = DistractionClassifier;
120	        let flags = c.classify("https://doubleclick.net/ad/123", "", "");
121	        assert!(flags.iter().any(|f| f.kind == DistractionKind::Ad));
122	    }
123	
124	    #[test]
125	    fn test_cookie_banner_in_text() {
126	        let c = DistractionClassifier;
127	        let flags = c.classify(
128	            "https://example.com",
129	            "We use cookies to improve your experience. Accept all cookies to continue.",
130	            "",
131	        );
132	        assert!(flags
133	            .iter()
134	            .any(|f| f.kind == DistractionKind::CookieBanner));
135	    }
136	
137	    #[test]
138	    fn test_clean_page_no_flags() {
139	        let c = DistractionClassifier;
140	        let flags = c.classify(
141	            "https://example.com/docs",
142	            "API reference documentation for the library.",
143	            r#"<div class="content">docs</div>"#,
144	        );
145	        assert!(flags.is_empty());
146	    }
147	
148	    #[test]
149	    fn test_deduplication_keeps_higher_confidence() {
150	        let c = DistractionClassifier;
151	        // "ad" in URL (0.95) + ad in content (0.9 for ad_blocker_wall)
152	        let flags = c.classify(
153	            "https://doubleclick.net/ad/123",
154	            "Ad blocker detected! Please disable your ad blocker to continue.",
155	            "",
156	        );
157	        let ad_flags: Vec<_> = flags
158	            .iter()
159	            .filter(|f| f.kind == DistractionKind::Ad)
160	            .collect();
161	        assert_eq!(ad_flags.len(), 1);
162	        assert!(ad_flags[0].confidence >= 0.9);
163	    }
164	
165	    #[test]
166	    fn test_css_popup_class() {
167	        let c = DistractionClassifier;
168	        let flags = c.classify(
169	            "https://example.com",
170	            "",
171	            r#"<div class="popup-overlay">Sign up now</div>"#,
172	        );
173	        assert!(flags.iter().any(|f| f.kind == DistractionKind::Popup));
174	    }
175	}
