1	//! 4-level cost circuit breaker.
2	//!
3	//! Transitions are one-way within a session (tightening only):
4	//! Normal → Conservative → Critical → Emergency
5	//!
6	//! The circuit breaker RESETS to Normal when a new session starts
7	//! (fresh budget). It does not auto-recover within a session.
8	
9	use ans_core::budget::BudgetMode;
10	
11	/// The circuit breaker state machine.
12	pub struct CircuitBreaker {
13	    mode: BudgetMode,
14	}
15	
16	impl CircuitBreaker {
17	    pub fn new() -> Self {
18	        Self {
19	            mode: BudgetMode::Normal,
20	        }
21	    }
22	
23	    pub fn current_mode(&self) -> BudgetMode {
24	        self.mode
25	    }
26	
27	    pub fn update(&mut self, remaining_pct: f32) {
28	        let new_mode = BudgetMode::from_remaining_pct(remaining_pct);
29	        if new_mode > self.mode {
30	            self.mode = new_mode;
31	        }
32	    }
33	}
34	
35	impl Default for CircuitBreaker {
36	    fn default() -> Self {
37	        Self::new()
38	    }
39	}
