1	//! Budget tracker — per-goal and global (per-API-key) spend tracking.
2	//!
3	//! Before any LLM/Vision API call, the tracker:
4	//! 1. Checks remaining budget → updates circuit breaker mode
5	//! 2. If mode disallows the call → returns cached/fallback response
6	//! 3. If allowed → tracks actual token usage from API response
7	//! 4. Updates spend counters
8	
9	use crate::circuit_breaker::CircuitBreaker;
10	use ans_core::budget::BudgetMode;
11	
12	/// Global budget configuration.
13	#[derive(Debug, Clone)]
14	pub struct BudgetConfig {
15	    pub default_per_goal_cents: u32,
16	    pub daily_spend_limit_cents: u32,
17	    pub normal_threshold_pct: f32,
18	    pub conservative_threshold_pct: f32,
19	    pub critical_threshold_pct: f32,
20	}
21	
22	impl Default for BudgetConfig {
23	    fn default() -> Self {
24	        Self {
25	            default_per_goal_cents: 500,
26	            daily_spend_limit_cents: 5000,
27	            normal_threshold_pct: 20.0,
28	            conservative_threshold_pct: 10.0,
29	            critical_threshold_pct: 5.0,
30	        }
31	    }
32	}
33	
34	/// Thread-safe global budget tracker.
35	///
36	/// Tracks spend across all goals for a single API key. Circuit breaker
37	/// tightens as daily budget is consumed. Per-goal trackers are created
38	/// on demand with their own budget caps.
39	pub struct BudgetTracker {
40	    config: BudgetConfig,
41	    breaker: CircuitBreaker,
42	    /// Total spent today across all goals.
43	    daily_spent_cents: u32,
44	    /// Total spent since tracker creation.
45	    total_spent_cents: u32,
46	}
47	
48	impl BudgetTracker {
49	    pub fn new(config: BudgetConfig) -> Self {
50	        Self {
51	            config,
52	            breaker: CircuitBreaker::new(),
53	            daily_spent_cents: 0,
54	            total_spent_cents: 0,
55	        }
56	    }
57	
58	    /// Current budget mode based on daily spend vs daily limit.
59	    pub fn mode(&self) -> BudgetMode {
60	        self.breaker.current_mode()
61	    }
62	
63	    /// Remaining daily budget percentage.
64	    pub fn remaining_pct(&self) -> f32 {
65	        if self.config.daily_spend_limit_cents == 0 {
66	            return 0.0;
67	        }
68	        let remaining = self
69	            .config
70	            .daily_spend_limit_cents
71	            .saturating_sub(self.daily_spent_cents);
72	        (remaining as f32 / self.config.daily_spend_limit_cents as f32) * 100.0
73	    }
74	
75	    /// Track spend against the daily budget. Updates circuit breaker.
76	    pub fn track_spend(&mut self, cost_cents: u32) {
77	        self.daily_spent_cents = self.daily_spent_cents.saturating_add(cost_cents);
78	        self.total_spent_cents = self.total_spent_cents.saturating_add(cost_cents);
79	        self.breaker.update(self.remaining_pct());
80	    }
81	
82	    /// Get the full budget status snapshot.
83	    pub fn status(&self) -> BudgetStatus {
84	        BudgetStatus {
85	            mode: self.mode(),
86	            budget_cents: self.config.daily_spend_limit_cents,
87	            spent_cents: self.total_spent_cents,
88	            remaining_pct: self.remaining_pct(),
89	            daily_spend_limit_cents: self.config.daily_spend_limit_cents,
90	            daily_spent_cents: self.daily_spent_cents,
91	        }
92	    }
93	
94	    /// Update the budget configuration. Resets circuit breaker
95	    /// if the daily limit was increased.
96	    pub fn configure(&mut self, config: BudgetConfig) {
97	        let limit_increased = config.daily_spend_limit_cents > self.config.daily_spend_limit_cents;
98	        self.config = config;
99	        if limit_increased {
100	            self.breaker = CircuitBreaker::new();
101	            self.breaker.update(self.remaining_pct());
102	        }
103	    }
104	
105	    /// Current config, for serialization.
106	    pub fn config(&self) -> &BudgetConfig {
107	        &self.config
108	    }
109	}
