769	/// Convert a proto [`ans_proto::ans::EyeReport`] to core [`ans_core::signal::EyeReport`].
770	/// Returns `None` if the eye_name is unrecognized or the content is missing.
771	fn proto_to_core_eye_report(
772	    proto: &ans_proto::ans::EyeReport,
773	) -> Option<ans_core::signal::EyeReport> {
774	    use ans_proto::ans::eye_report::Content;
775	
776	    let eye_name = match proto.eye_name.as_str() {
777	        "dom_reader" => EyeName::DomReader,
778	        "vision" => EyeName::Vision,
779	        "page_diff" => EyeName::PageDiff,
780	        "goal_verifier" => EyeName::GoalVerifier,
781	        "error_detector" => EyeName::ErrorDetector,
782	        _ => return None,
783	    };
784	
785	    let content = match &proto.content {
786	        Some(Content::Dom(dom)) => EyeReportContent::DomReport {
787	            elements: vec![],
788	            interactive: vec![],
789	            mode: dom
790	                .dom
791	                .as_ref()
792	                .map(|d| match d.mode.as_str() {
793	                    "text_only" => DistillMode::TextOnly,
794	                    "input_fields" => DistillMode::InputFields,
795	                    _ => DistillMode::AllFields,
796	                })
797	                .unwrap_or(DistillMode::AllFields),
798	        },
799	        Some(Content::Vision(v)) => EyeReportContent::VisionReport {
800	            visible_elements: v.visible_elements.clone(),
801	            overlays: v.overlays.clone(),
802	            blocked_regions: v.blocked_regions.clone(),
803	            page_type: v.page_type.clone(),
804	            anomalies: v.anomalies.clone(),
805	            raw_response: v.raw_response.clone(),
806	        },
807	        Some(Content::Diff(d)) => {
808	            let diff_report = d.diff.as_ref();
809	            EyeReportContent::DiffReport {
810	                added: diff_report.map_or(vec![], |r| {
811	                    r.added.iter().map(|e| e.selector.clone()).collect()
812	                }),
813	                removed: diff_report.map_or(vec![], |r| {
814	                    r.removed.iter().map(|e| e.selector.clone()).collect()
815	                }),
816	                modified: diff_report.map_or(vec![], |r| {
817	                    r.modified.iter().map(|m| m.selector.clone()).collect()
818	                }),
819	                visual_diff_pct: diff_report.map_or(0.0, |r| r.visual_diff_percentage),
820	                summary: diff_report.map_or(String::new(), |r| r.summary.clone()),
821	            }
822	        }
823	        Some(Content::Verification(v)) => EyeReportContent::Verification {
824	            sub_goal_advanced: v.criteria_status == "met",
825	            confidence: v.confidence,
826	            reasoning: v.reasoning.clone(),
827	            criteria_status: v.criteria_status.clone(),
828	        },
829	        Some(Content::Error(e)) => EyeReportContent::ErrorReport {
830	            failure_type: e.failure_type.clone(),
831	            description: e.description.clone(),
832	            recovery_actions: e.recovery_actions.clone(),
833	            should_retry: e.should_retry,
834	            max_retries: e.max_retries as u32,
835	        },
836	        None => return None,
837	    };
838	
839	    Some(ans_core::signal::EyeReport {
840	        eye_name,
841	        timestamp: chrono::Utc::now(),
842	        confidence: proto.confidence,
843	        goal_relevance: proto.goal_relevance,
844	        content,
845	    })
846	}
