848	/// Format the oneof eye report content into a readable string.
849	fn format_eye_content(content: &Option<ans_proto::ans::eye_report::Content>) -> String {
850	    use ans_proto::ans::eye_report::Content;
851	    match content {
852	        Some(Content::Dom(dom)) => {
853	            format!(
854	                "DOM: {} elements, {} interactive",
855	                dom.dom.as_ref().map_or(0, |d| d.elements.len() as i32),
856	                dom.focused_elements.len()
857	            )
858	        }
859	        Some(Content::Vision(v)) => {
860	            format!(
861	                "Vision: {} visible, {} overlays, type={}",
862	                v.visible_elements.len(),
863	                v.overlays.len(),
864	                v.page_type
865	            )
866	        }
867	        Some(Content::Diff(d)) => {
868	            format!(
869	                "Diff: {}% visual change",
870	                d.diff.as_ref().map_or(0.0, |r| r.visual_diff_percentage)
871	            )
872	        }
873	        Some(Content::Verification(v)) => {
874	            format!(
875	                "Verify: {} (confidence={:.0}%)",
876	                v.criteria_status,
877	                v.confidence * 100.0
878	            )
879	        }
880	        Some(Content::Error(e)) => {
881	            format!("Error: {} — {}", e.failure_type, e.description)
882	        }
883	        None => "no content".into(),
884	    }
885	}
