1	//! Signal router — the central nervous system hub.
2	//!
3	//! Receives EyeReports from all 5 eyes, scores goal relevance,
4	//! suppresses noise, resolves contradictions, and emits a unified
5	//! RoutedSignal to the Decision Intelligence Layer.
6	//!
7	//! Pipeline:
8	//! 1. Score each report for goal relevance
9	//! 2. Filter out noise (relevance below threshold)
10	//! 3. Amplify high-relevance signals
11	//! 4. Resolve cross-eye contradictions
12	//! 5. Synthesize unified RoutedSignal
13	
14	use ans_core::signal::{DistractionAlert, EyeName, EyeReport, EyeReportContent, RoutedSignal};
15	
16	use crate::contradiction::ContradictionResolver;
17	
18	/// Minimum relevance score for a report to pass noise suppression.
19	const NOISE_THRESHOLD: f32 = 0.15;
20	
21	/// Eye-specific base weight for relevance scoring.
22	fn eye_weight(eye: EyeName) -> f32 {
23	    match eye {
24	        EyeName::GoalVerifier => 0.35,
25	        EyeName::PageDiff => 0.25,
26	        EyeName::DomReader => 0.20,
27	        EyeName::Vision => 0.15,
28	        EyeName::ErrorDetector => 0.05,
29	    }
30	}
31	
32	/// The signal router. Single instance per daemon, shared across sessions.
33	pub struct SignalRouter {
34	    resolver: ContradictionResolver,
35	}
36	
37	impl SignalRouter {
38	    pub fn new() -> Self {
39	        Self {
40	            resolver: ContradictionResolver,
41	        }
42	    }
43	
44	    /// Route a batch of eye reports into a unified signal.
45	    pub fn route(&self, reports: &[EyeReport]) -> RoutedSignal {
46	        if reports.is_empty() {
47	            return RoutedSignal {
48	                unified_perception: String::new(),
49	                alerts: Vec::new(),
50	                confidence: 0.0,
51	                recommended_action_hint: None,
52	                contradictions: Vec::new(),
53	            };
54	        }
55	
56	        // 1. Score and filter
57	        let scored: Vec<ScoredReport> = reports
58	            .iter()
59	            .map(|r| ScoredReport {
60	                report: r,
61	                relevance: compute_relevance(r),
62	            })
63	            .collect();
64	
65	        // 2. Suppress noise
66	        let active: Vec<&ScoredReport> = scored
67	            .iter()
68	            .filter(|s| s.relevance >= NOISE_THRESHOLD)
69	            .collect();
70	
71	        let reports_for_resolution: Vec<EyeReport> = if active.is_empty() {
72	            // Everything was noise — keep the highest-relevance one as fallback
73	            scored
74	                .iter()
75	                .max_by(|a, b| a.relevance.partial_cmp(&b.relevance).unwrap())
76	                .map(|s| s.report.clone())
77	                .into_iter()
78	                .collect()
79	        } else {
80	            active.iter().map(|s| s.report.clone()).collect()
81	        };
82	
83	        // 3. Resolve contradictions
84	        let contradictions = self.resolver.resolve_all(&reports_for_resolution);
85	
86	        // 4. Synthesize unified perception
87	        let parts: Vec<String> = reports_for_resolution
88	            .iter()
89	            .map(format_eye_summary)
90	            .collect();
91	
92	        let unified_perception = parts.join(" | ");
93	
94	        // 5. Compute aggregate confidence
95	        let confidence = if reports_for_resolution.is_empty() {
96	            0.0
97	        } else {
98	            let total: f32 = reports_for_resolution
99	                .iter()
100	                .map(|r| r.confidence * eye_weight(r.eye_name))
101	                .sum();
102	            let max_possible: f32 = reports_for_resolution
103	                .iter()
104	                .map(|r| eye_weight(r.eye_name))
105	                .sum();
106	            if max_possible > 0.0 {
107	                (total / max_possible).clamp(0.0, 1.0)
108	            } else {
109	                0.0
110	            }
111	        };
112	
113	        // 6. Generate action hint
114	        let hint = generate_hint(&reports_for_resolution, &contradictions);
115	
116	        // 7. Collect alerts from error reports
117	        let alerts = collect_alerts(&reports_for_resolution);
118	
119	        RoutedSignal {
120	            unified_perception,
121	            alerts,
122	            confidence,
123	            recommended_action_hint: hint,
124	            contradictions,
125	        }
126	    }
127	}
128	
129	impl Default for SignalRouter {
130	    fn default() -> Self {
131	        Self::new()
132	    }
133	}
134	
135	// ── Internal types ─────────────────────────────────────────────────────
136	
137	struct ScoredReport<'a> {
138	    report: &'a EyeReport,
139	    relevance: f32,
140	}
141	
142	// ── Relevance scoring ──────────────────────────────────────────────────
143	
144	fn compute_relevance(report: &EyeReport) -> f32 {
145	    let base = eye_weight(report.eye_name);
146	    let confidence_factor = report.confidence;
147	    let content_boost = content_relevance_boost(&report.content);
148	    let goal_relevance = report.goal_relevance;
149	
150	    // Weighted blend: eye authority, confidence, content signals, goal alignment
151	    (base * 0.3 + confidence_factor * 0.25 + content_boost * 0.15 + goal_relevance * 0.3)
152	        .clamp(0.0, 1.0)
153	}
154	
155	fn content_relevance_boost(content: &EyeReportContent) -> f32 {
156	    match content {
157	        EyeReportContent::DomReport {
158	            interactive, mode, ..
159	        } => {
160	            let mut boost: f32 = 0.3;
161	            // More interactive elements = more actionable page
162	            if interactive.len() > 5 {
163	                boost += 0.2;
164	            }
165	            if *mode == ans_core::distill::DistillMode::InputFields {
166	                boost += 0.1; // form interaction is high-signal
167	            }
168	            boost.clamp(0.0, 1.0)
169	        }
170	        EyeReportContent::VisionReport {
171	            anomalies,
172	            overlays,
173	            ..
174	        } => {
175	            if !anomalies.is_empty() || !overlays.is_empty() {
176	                0.7 // anomalies are high-signal
177	            } else {
178	                0.3
179	            }
180	        }
181	        EyeReportContent::DiffReport {
182	            visual_diff_pct,
183	            summary,
184	            ..
185	        } => {
186	            if *visual_diff_pct > 20.0 {
187	                0.8
188	            } else if summary.contains("content_update") || summary.contains("form_update") {
189	                0.6
190	            } else if summary.contains("navigation") {
191	                0.4
192	            } else {
193	                0.2
194	            }
195	        }
196	        EyeReportContent::Verification {
197	            sub_goal_advanced,
198	            confidence,
199	            ..
200	        } => {
201	            if *sub_goal_advanced {
202	                0.8 * confidence
203	            } else {
204	                0.3 * confidence
205	            }
206	        }
207	        EyeReportContent::ErrorReport { .. } => 0.9, // errors are always high-signal
208	    }
209	}
210	
211	// ── Perception formatting ──────────────────────────────────────────────
212	
213	fn format_eye_summary(report: &EyeReport) -> String {
214	    let content_summary = match &report.content {
215	        EyeReportContent::DomReport {
216	            elements,
217	            interactive,
218	            mode,
219	        } => {
220	            format!(
221	                "DOM({}): {} el, {} interactive",
222	                mode.as_str(),
223	                elements.len(),
224	                interactive.len()
225	            )
226	        }
227	        EyeReportContent::VisionReport {
228	            visible_elements,
229	            overlays,
230	            page_type,
231	            anomalies,
232	            ..
233	        } => {
234	            let mut s = format!(
235	                "Vision: {} visible, type={}",
236	                visible_elements.len(),
237	                page_type
238	            );
239	            if !overlays.is_empty() {
240	                s.push_str(&format!(", {} overlays", overlays.len()));
241	            }
242	            if !anomalies.is_empty() {
243	                s.push_str(&format!(", {} anomalies", anomalies.len()));
244	            }
245	            s
246	        }
247	        EyeReportContent::DiffReport {
248	            visual_diff_pct,
249	            summary,
250	            ..
251	        } => {
252	            format!("Diff: {:.0}% change ({})", visual_diff_pct, summary)
253	        }
254	        EyeReportContent::Verification {
255	            sub_goal_advanced,
256	            confidence,
257	            criteria_status,
258	            ..
259	        } => {
260	            format!(
261	                "Verify: {} (conf={:.0}%, criteria={})",
262	                if *sub_goal_advanced {
263	                    "advanced"
264	                } else {
265	                    "no progress"
266	                },
267	                confidence * 100.0,
268	                criteria_status,
269	            )
270	        }
271	        EyeReportContent::ErrorReport {
272	            failure_type,
273	            description,
274	            ..
275	        } => {
276	            format!("Error: {} — {}", failure_type, description)
277	        }
278	    };
279	
280	    format!(
281	        "[{} r={:.0}% c={:.0}%] {}",
282	        report.eye_name.as_str(),
283	        report.goal_relevance * 100.0,
284	        report.confidence * 100.0,
285	        content_summary,
286	    )
287	}
