289	// ── Action hint generation ─────────────────────────────────────────────
290	
291	fn generate_hint(reports: &[EyeReport], contradictions: &[String]) -> Option<String> {
292	    if !contradictions.is_empty() {
293	        return Some("Cross-eye contradictions detected — verify before acting".into());
294	    }
295	
296	    // Check for error reports
297	    let errors: Vec<_> = reports
298	        .iter()
299	        .filter(|r| matches!(r.content, EyeReportContent::ErrorReport { .. }))
300	        .collect();
301	
302	    if !errors.is_empty() {
303	        return Some("Errors detected — attempt recovery before proceeding".into());
304	    }
305	
306	    // Check for high-confidence verifier
307	    let verifications: Vec<_> = reports
308	        .iter()
309	        .filter(|r| matches!(r.content, EyeReportContent::Verification { .. }))
310	        .collect();
311	
312	    if let Some(v) = verifications.first() {
313	        if v.confidence > 0.8 && v.goal_relevance > 0.7 {
314	            if let EyeReportContent::Verification {
315	                sub_goal_advanced: true,
316	                ..
317	            } = &v.content
318	            {
319	                return Some("Goal progressing — continue current strategy".into());
320	            }
321	        }
322	    }
323	
324	    // Check for high-change diff
325	    let diffs: Vec<_> = reports
326	        .iter()
327	        .filter(|r| matches!(r.content, EyeReportContent::DiffReport { .. }))
328	        .collect();
329	
330	    if let Some(d) = diffs.first() {
331	        if let EyeReportContent::DiffReport {
332	            visual_diff_pct, ..
333	        } = &d.content
334	        {
335	            if *visual_diff_pct > 50.0 {
336	                return Some("Major page change — re-assess page state before acting".into());
337	            }
338	        }
339	    }
340	
341	    // Average relevance across all reports
342	    let avg_relevance: f32 =
343	        reports.iter().map(|r| r.goal_relevance).sum::<f32>() / reports.len().max(1) as f32;
344	
345	    if avg_relevance > 0.7 {
346	        Some("High goal relevance — prioritize action".into())
347	    } else if avg_relevance < 0.3 {
348	        Some("Low goal relevance — consider re-navigating".into())
349	    } else {
350	        None
351	    }
352	}
