354	// ── Alert collection ───────────────────────────────────────────────────
355	
356	fn collect_alerts(reports: &[EyeReport]) -> Vec<DistractionAlert> {
357	    let mut alerts = Vec::new();
358	
359	    for report in reports {
360	        match &report.content {
361	            EyeReportContent::VisionReport {
362	                anomalies,
363	                overlays,
364	                ..
365	            } => {
366	                for anomaly in anomalies {
367	                    alerts.push(DistractionAlert {
368	                        kind: "vision_anomaly".into(),
369	                        description: anomaly.clone(),
370	                        action_taken: "flagged for review".into(),
371	                    });
372	                }
373	                for overlay in overlays {
374	                    alerts.push(DistractionAlert {
375	                        kind: "overlay_detected".into(),
376	                        description: overlay.clone(),
377	                        action_taken: "dismiss before interaction".into(),
378	                    });
379	                }
380	            }
381	            EyeReportContent::ErrorReport {
382	                failure_type,
383	                description,
384	                should_retry,
385	                ..
386	            } => {
387	                alerts.push(DistractionAlert {
388	                    kind: format!("error_{}", failure_type),
389	                    description: description.clone(),
390	                    action_taken: if *should_retry {
391	                        "will retry".into()
392	                    } else {
393	                        "requires manual intervention".into()
394	                    },
395	                });
396	            }
397	            _ => {}
398	        }
399	    }
400	
401	    alerts
402	}
